 */
static int finish_with_semicolon(const char **cursor) {
    skip_spaces(cursor);

    if (**cursor != ';') {
        return PARSE_ERROR_MISSING_SEMICOLON;
    }

    (*cursor)++;
    skip_spaces(cursor);

